// Code Node: Pre-Processing & Metadata
const items = $input.all();

return items.map(item => {
    const attachment = item.json.attachments[0];

    // Extract email metadata
    item.json.emailSubject = item.json.subject || '';
    item.json.senderEmail = item.json.from?.address || 'user@example.com';
    item.json.senderName = item.json.from?.name || 'Unknown Sender';
    item.json.receivedDate = item.json.date || new Date().toISOString();
    item.json.gmailMessageId = item.json.id || '';

    // Attachment metadata
    item.json.attachmentName = attachment.name;
    item.json.attachmentSize = attachment.size || 0;
    item.json.attachmentMimeType = attachment.mimeType;

    // Generate processing ID
    item.json.processingId = `INV-${Date.now()}-${Math.random().toString(36).substring(2, 8).toUpperCase()}`;
    item.json.intakeTimestamp = new Date().toISOString();

    return item;
});

// Code Node: AI-Powered Financial Data Extraction
const item = $input.first();
const text = item.json.text || '';
const lines = text.split('\n');

// Enhanced pattern matching for invoice fields
const patterns = {
    // Amount patterns
    total: [
        /(?:total|amount due|balance due|grand total)[:\s]*\$?([0-9,]+\.\d{2})/i,
        /(?:total)[:\s]*([0-9,]+\.\d{2})/i,
        /\$([0-9,]+\.\d{2})(?:\s*(?:total|due))/i
    ],

    // Tax patterns
    tax: [
        /(?:tax|vat|gst|sales tax)[:\s]*\$?([0-9,]+\.\d{2})/i,
        /(?:tax amount)[:\s]*([0-9,]+\.\d{2})/i
    ],

    // Vendor patterns
    vendor: [
        /(?:from|vendor|supplier|bill from)[:\s]*([A-Za-z0-9\s&\.,'\-]+?)(?:\n|$)/i,
        /^([A-Z][A-Za-z0-9\s&\.,'\-]{3,40})$/m,  // Company name at start of line
        /(?:payable to)[:\s]*([A-Za-z0-9\s&\.,'\-]+)/i
    ],

    // Invoice number patterns
    invoiceNumber: [
        /(?:invoice|inv|bill)(?:\s*#|\s*no\.?|\s*number)[:\s]*([A-Z0-9\-]+)/i,
        /#([A-Z0-9\-]{3,20})/
    ],

    // Date patterns
    invoiceDate: [
        /(?:invoice date|date|issued)[:\s]*(\d{1,2}[/-]\d{1,2}[/-]\d{2,4})/i,
        /(\d{1,2}\/\d{1,2}\/\d{2,4})/
    ],

    // Due date patterns
    dueDate: [
        /(?:due date|payment due)[:\s]*(\d{1,2}[/-]\d{1,2}[/-]\d{2,4})/i
    ],

    // Subtotal patterns
    subtotal: [
        /(?:subtotal|sub-total)[:\s]*\$?([0-9,]+\.\d{2})/i
    ]
};

// Function to try multiple patterns
function extractField(patterns, text) {
    for (const pattern of patterns) {
        const match = text.match(pattern);
        if (match && match[1]) {
            return match[1].trim();
        }
    }
    return null;
}

// Extract all fields
const totalStr = extractField(patterns.total, text);
const taxStr = extractField(patterns.tax, text);
const subtotalStr = extractField(patterns.subtotal, text);
const vendorRaw = extractField(patterns.vendor, text);
const invoiceNumber = extractField(patterns.invoiceNumber, text);
const invoiceDate = extractField(patterns.invoiceDate, text);
const dueDate = extractField(patterns.dueDate, text);

// Parse amounts
const totalAmount = totalStr ? parseFloat(totalStr.replace(/[,$]/g, '')) : 0;
const taxAmount = taxStr ? parseFloat(taxStr.replace(/[,$]/g, '')) : 0;
const subtotalAmount = subtotalStr ? parseFloat(subtotalStr.replace(/[,$]/g, '')) : (totalAmount - taxAmount);

// Clean vendor name
const vendorName = vendorRaw ? vendorRaw.replace(/[\n\r]/g, ' ').trim().substring(0, 100) : 'Unknown Vendor';

// Calculate confidence score
let confidence = 0;
let confidenceFactors = [];

if (totalAmount > 0) {
    confidence += 0.4;
    confidenceFactors.push('amount_found');
}
if (vendorRaw && vendorRaw.length > 3) {
    confidence += 0.3;
    confidenceFactors.push('vendor_found');
}
if (invoiceNumber) {
    confidence += 0.15;
    confidenceFactors.push('invoice_number_found');
}
if (taxAmount > 0) {
    confidence += 0.1;
    confidenceFactors.push('tax_found');
}
if (invoiceDate) {
    confidence += 0.05;
    confidenceFactors.push('date_found');
}

// Validation checks
const isValidAmount = totalAmount > 0 && totalAmount < 1000000;
const isValidVendor = vendorName !== 'Unknown Vendor' && vendorName.length > 2;
const mathCheck = Math.abs((subtotalAmount + taxAmount) - totalAmount) < 1; // Allow $1 rounding

if (mathCheck) {
    confidence += 0.05;
    confidenceFactors.push('math_verified');
}

// Build structured output
item.json.extracted = {
    vendorName: vendorName,
    totalAmount: totalAmount,
    taxAmount: taxAmount,
    subtotalAmount: subtotalAmount,
    invoiceNumber: invoiceNumber || 'NOT_FOUND',
    invoiceDate: invoiceDate || item.json.receivedDate?.split('T')[0] || '',
    dueDate: dueDate || '',
    confidence: Math.min(confidence, 0.99),
    confidenceFactors: confidenceFactors,
    validationStatus: isValidAmount && isValidVendor ? 'PASS' : 'REVIEW_REQUIRED',
    extractedAt: new Date().toISOString(),
    rawTextLength: text.length
};

// Flatten for easier access
item.json.vendorName = vendorName;
item.json.totalAmount = totalAmount;
item.json.taxAmount = taxAmount;
item.json.subtotalAmount = subtotalAmount;
item.json.invoiceNumber = invoiceNumber || 'NOT_FOUND';
item.json.invoiceDate = invoiceDate || item.json.receivedDate?.split('T')[0] || '';
item.json.dueDate = dueDate || '';
item.json.confidence = item.json.extracted.confidence;
item.json.validationStatus = item.json.extracted.validationStatus;

// Categorization
if (totalAmount > 5000) {
    item.json.category = 'HIGH_VALUE';
} else if (totalAmount > 1000) {
    item.json.category = 'MEDIUM_VALUE';
} else {
    item.json.category = 'LOW_VALUE';
}

// Risk flag
item.json.requiresReview = confidence < 0.7 || totalAmount > 5000;

return item;

